import{_ as s,c as i,a0 as e,o as t}from"./chunks/framework.Bv0BGHPE.js";const k=JSON.parse('{"title":"MiMusic 常见问题解答 (FAQ)","description":"","frontmatter":{"title":"MiMusic 常见问题解答 (FAQ)"},"headers":[],"relativePath":"issues/1.md","filePath":"issues/1.md","lastUpdated":1774831759000}'),l={name:"issues/1.md"};function h(n,a,r,o,p,d){return t(),i("div",null,a[0]||(a[0]=[e(`<h1 id="mimusic-常见问题解答-faq" tabindex="-1">MiMusic 常见问题解答 (FAQ) <a class="header-anchor" href="#mimusic-常见问题解答-faq" aria-label="Permalink to &quot;MiMusic 常见问题解答 (FAQ)&quot;" target="_self">​</a></h1><h2 id="安装与部署" tabindex="-1">安装与部署 <a class="header-anchor" href="#安装与部署" aria-label="Permalink to &quot;安装与部署&quot;" target="_self">​</a></h2><h3 id="q-我应该如何下载-mimusic" tabindex="-1">Q: 我应该如何下载 MiMusic？ <a class="header-anchor" href="#q-我应该如何下载-mimusic" aria-label="Permalink to &quot;Q: 我应该如何下载 MiMusic？&quot;" target="_self">​</a></h3><p>A: 从 <a href="https://github.com/mimusic-org/mimusic/releases" target="_self">GitHub Releases</a> 下载适合您系统的版本。支持 Linux、macOS 和 Windows 平台，提供二进制文件和 Docker 镜像两种部署方式。</p><h3 id="q-支持哪些操作系统和架构" tabindex="-1">Q: 支持哪些操作系统和架构？ <a class="header-anchor" href="#q-支持哪些操作系统和架构" aria-label="Permalink to &quot;Q: 支持哪些操作系统和架构？&quot;" target="_self">​</a></h3><p>A: 支持以下平台：</p><ul><li><strong>Linux</strong>: x86_64、ARM64、ARMv7</li><li><strong>macOS</strong>: x86_64 (Intel)、ARM64 (Apple Silicon)</li><li><strong>Windows</strong>: x86_64、ARM64</li></ul><h3 id="q-docker-部署时容器无法访问音乐文件怎么办" tabindex="-1">Q: Docker 部署时容器无法访问音乐文件怎么办？ <a class="header-anchor" href="#q-docker-部署时容器无法访问音乐文件怎么办" aria-label="Permalink to &quot;Q: Docker 部署时容器无法访问音乐文件怎么办？&quot;" target="_self">​</a></h3><p>A: 确保使用绝对路径挂载卷：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /absolute/path/to/music:/app/music</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /absolute/path/to/data:/app/data</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  hanxi/mimusic:latest</span></span></code></pre></div><h2 id="配置与运行" tabindex="-1">配置与运行 <a class="header-anchor" href="#配置与运行" aria-label="Permalink to &quot;配置与运行&quot;" target="_self">​</a></h2><h3 id="q-如何修改服务端口" tabindex="-1">Q: 如何修改服务端口？ <a class="header-anchor" href="#q-如何修改服务端口" aria-label="Permalink to &quot;Q: 如何修改服务端口？&quot;" target="_self">​</a></h3><p>A: 有两种方式：</p><ol><li>使用命令行参数：<code>./mimusic --port 8080</code></li><li>使用环境变量：<code>PORT=8080 ./mimusic</code></li></ol><p>默认端口为 <strong>58091</strong>。</p><h3 id="q-如何配置管理员账号" tabindex="-1">Q: 如何配置管理员账号？ <a class="header-anchor" href="#q-如何配置管理员账号" aria-label="Permalink to &quot;Q: 如何配置管理员账号？&quot;" target="_self">​</a></h3><p>A: 通过环境变量设置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADMIN_USERNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">admin</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADMIN_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your_secure_password</span></span></code></pre></div><p>或在 Docker 中使用 <code>-e</code> 参数传递。</p><h3 id="q-支持哪些音乐文件格式" tabindex="-1">Q: 支持哪些音乐文件格式？ <a class="header-anchor" href="#q-支持哪些音乐文件格式" aria-label="Permalink to &quot;Q: 支持哪些音乐文件格式？&quot;" target="_self">​</a></h3><p>A: 支持主流音频格式：<strong>MP3、FLAC、WAV、APE、OGG、M4A</strong> 等。</p><h2 id="使用问题" tabindex="-1">使用问题 <a class="header-anchor" href="#使用问题" aria-label="Permalink to &quot;使用问题&quot;" target="_self">​</a></h2><h3 id="q-音乐文件无法播放怎么办" tabindex="-1">Q: 音乐文件无法播放怎么办？ <a class="header-anchor" href="#q-音乐文件无法播放怎么办" aria-label="Permalink to &quot;Q: 音乐文件无法播放怎么办？&quot;" target="_self">​</a></h3><p>A: 检查以下几点：</p><ol><li>确认音乐文件格式是否受支持</li><li>确保音乐文件路径配置正确</li><li>检查文件权限是否允许读取</li><li>可选安装 <code>ffprobe</code> 以获取更完整的音频技术参数</li></ol><h3 id="q-如何扫描音乐库" tabindex="-1">Q: 如何扫描音乐库？ <a class="header-anchor" href="#q-如何扫描音乐库" aria-label="Permalink to &quot;Q: 如何扫描音乐库？&quot;" target="_self">​</a></h3><p>A: 启动服务后，在 Web 界面中点击 <strong>&quot;扫描&quot;</strong> 按钮，系统会自动扫描配置的音乐目录并提取元数据。</p><h2 id="升级与维护" tabindex="-1">升级与维护 <a class="header-anchor" href="#升级与维护" aria-label="Permalink to &quot;升级与维护&quot;" target="_self">​</a></h2><h3 id="q-如何升级或更新-mimusic" tabindex="-1">Q: 如何升级或更新 MiMusic？ <a class="header-anchor" href="#q-如何升级或更新-mimusic" aria-label="Permalink to &quot;Q: 如何升级或更新 MiMusic？&quot;" target="_self">​</a></h3><p>A:</p><ol><li>下载最新版本的二进制文件或 Docker 镜像</li><li>停止当前服务</li><li>替换二进制文件或更新 Docker 镜像</li><li>重新启动服务</li></ol><p>如果升级后出现异常，可尝试删除 <code>data/mimusic.db</code> 后重启（会丢失用户数据）。</p><h3 id="q-如何验证下载文件的完整性" tabindex="-1">Q: 如何验证下载文件的完整性？ <a class="header-anchor" href="#q-如何验证下载文件的完整性" aria-label="Permalink to &quot;Q: 如何验证下载文件的完整性？&quot;" target="_self">​</a></h3><p>A: 每个 Release 都包含 <code>checksums.txt</code> 文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/mimusic-org/mimusic/releases/latest/download/checksums.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checksums.txt</span></span></code></pre></div><h3 id="q-如何查看当前版本" tabindex="-1">Q: 如何查看当前版本？ <a class="header-anchor" href="#q-如何查看当前版本" aria-label="Permalink to &quot;Q: 如何查看当前版本？&quot;" target="_self">​</a></h3><p>A:</p><ul><li>命令行：<code>./mimusic -help</code>（查看帮助信息和可用参数）</li><li>API: <code>curl http://localhost:58091/api/v1/version</code></li></ul><p><strong>注意</strong>：MiMusic 不支持 <code>--version</code> 参数，请使用 <code>-help</code> 查看命令行帮助。</p><h2 id="api-使用" tabindex="-1">API 使用 <a class="header-anchor" href="#api-使用" aria-label="Permalink to &quot;API 使用&quot;" target="_self">​</a></h2><h3 id="q-如何通过-api-获取访问令牌" tabindex="-1">Q: 如何通过 API 获取访问令牌？ <a class="header-anchor" href="#q-如何通过-api-获取访问令牌" aria-label="Permalink to &quot;Q: 如何通过 API 获取访问令牌？&quot;" target="_self">​</a></h3><p>A:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:58091/api/v1/auth/login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;username&quot;:&quot;admin&quot;,&quot;password&quot;:&quot;your_password&quot;}&#39;</span></span></code></pre></div><p>响应中包含 <code>access_token</code>，用于后续 API 请求的认证。</p><h3 id="q-如何在-api-请求中使用-token" tabindex="-1">Q: 如何在 API 请求中使用 Token？ <a class="header-anchor" href="#q-如何在-api-请求中使用-token" aria-label="Permalink to &quot;Q: 如何在 API 请求中使用 Token？&quot;" target="_self">​</a></h3><p>A: 在请求头中添加 Authorization：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:58091/api/v1/songs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer YOUR_ACCESS_TOKEN&quot;</span></span></code></pre></div><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;" target="_self">​</a></h2><h3 id="q-必须安装-ffprobe-吗" tabindex="-1">Q: 必须安装 ffprobe 吗？ <a class="header-anchor" href="#q-必须安装-ffprobe-吗" aria-label="Permalink to &quot;Q: 必须安装 ffprobe 吗？&quot;" target="_self">​</a></h3><p>A: <strong>不是必须的</strong>。MiMusic 可以不依赖 ffprobe 正常运行，但安装后可以获取更完整的音频技术参数信息。</p><hr><h2 id="获取帮助" tabindex="-1">获取帮助 <a class="header-anchor" href="#获取帮助" aria-label="Permalink to &quot;获取帮助&quot;" target="_self">​</a></h2><ul><li><strong>GitHub Issues</strong>: <a href="https://github.com/mimusic-org/mimusic/issues" target="_self">https://github.com/mimusic-org/mimusic/issues</a></li><li><strong>项目主页</strong>: <a href="https://github.com/mimusic-org/mimusic" target="_self">https://github.com/mimusic-org/mimusic</a></li></ul><h2 id="评论" tabindex="-1">评论 <a class="header-anchor" href="#评论" aria-label="Permalink to &quot;评论&quot;" target="_self">​</a></h2><p>没有评论。 <a href="https://github.com/mimusic-org/mimusic/issues/1" target="_self">链接到 GitHub Issue</a></p>`,55)]))}const u=s(l,[["render",h]]);export{k as __pageData,u as default};
